#!/usr/bin/env node
// E2E tests -- auto-generated by Clear compiler
// Run: node test.js
// Requires: server running on localhost:3000

const BASE = process.env.TEST_URL || "http://localhost:3000";
let passed = 0, failed = 0;
let _emailCounter = 0;
let _uniqueCounter = 0;
function _uniqueEmail() { return "test" + (++_emailCounter) + "@example.com"; }
function _uniqueText(base) { return base + "_" + (++_uniqueCounter); }

// Note: for clean re-runs, delete clear-data.json before starting the server
// unique constraints may cause 500s if stale data exists from a previous run

// Generate a test auth token using the same runtime as the server
const auth = require("./clear-runtime/auth");
const TEST_TOKEN = auth.createToken({ id: 1, role: "admin", email: "test@test.com" });
const AUTH_HEADERS = { "Authorization": "Bearer " + TEST_TOKEN, "Content-Type": "application/json" };

// IDs created by setup steps, used by dependent tests
const createdIds = {};

async function test(name, fn) {
  try {
    await fn();
    passed++;
    console.log("PASS:", name);
  } catch (err) {
    failed++;
    console.log("FAIL:", name, "-", err.message);
  }
}

function assert(condition, msg) { if (!condition) throw new Error(msg); }

async function run() {
  // Setup: create a product so dependent tests have a valid product_id
  await test("SETUP: create product for FK dependencies", async () => {
    const r = await fetch(BASE + "/api/products", {
      method: "POST", headers: AUTH_HEADERS,
      body: JSON.stringify({"name":"Test value","price":42})
    });
    assert(r.status === 201, "Expected 201, got " + r.status);
    const data = await r.json();
    assert(data.id, "Setup product should return an id");
    createdIds["product"] = data.id;
  });

  await test("GET /api/products returns 200", async () => {
    const r = await fetch(BASE + "/api/products");
    assert(r.status === 200, "Expected 200, got " + r.status);
  });

  await test("GET /api/products/:id returns 200 or 404", async () => {
    const r = await fetch(BASE + "/api/products/1");
    assert(r.status === 200 || r.status === 404, "Expected 200 or 404, got " + r.status);
  });

  await test("GET /api/orders returns 200", async () => {
    const r = await fetch(BASE + "/api/orders", { headers: AUTH_HEADERS });
    assert(r.status === 200, "Expected 200, got " + r.status);
  });

  await test("GET /api/orders/:id returns 200 or 404", async () => {
    const r = await fetch(BASE + "/api/orders/1", { headers: AUTH_HEADERS });
    assert(r.status === 200 || r.status === 404, "Expected 200 or 404, got " + r.status);
  });

  await test("GET /api/health returns 200", async () => {
    const r = await fetch(BASE + "/api/health");
    assert(r.status === 200, "Expected 200, got " + r.status);
  });

  await test("POST /api/orders with valid data returns 201", async () => {
    const payload = {"product_id":"Test value","quantity":42,"user_id":"Test value","total":42};
    payload["product_id"] = createdIds["product"];
    payload["user_id"] = _uniqueText("user_id");
    const r = await fetch(BASE + "/api/orders", {
      method: "POST", headers: AUTH_HEADERS,
      body: JSON.stringify(payload)
    });
    assert(r.status === 201, "Expected 201, got " + r.status);
    const data = await r.json();
    assert(data.id, "Response should have an id");
  });

  await test("POST /api/orders with no body returns 400", async () => {
    const r = await fetch(BASE + "/api/orders", { method: "POST", headers: { "Authorization": "Bearer " + TEST_TOKEN } });
    assert(r.status === 400, "Expected 400, got " + r.status);
  });

  await test("POST /api/orders with empty required field returns 400", async () => {
    const r = await fetch(BASE + "/api/orders", {
      method: "POST", headers: AUTH_HEADERS,
      body: JSON.stringify({ product_id: "" })
    });
    assert(r.status === 400, "Expected 400, got " + r.status);
  });

  await test("POST /api/products with valid data returns 201", async () => {
    const payload = {"name":"Test value","price":42};
    payload["name"] = _uniqueText("name");
    const r = await fetch(BASE + "/api/products", {
      method: "POST", headers: AUTH_HEADERS,
      body: JSON.stringify(payload)
    });
    assert(r.status === 201, "Expected 201, got " + r.status);
    const data = await r.json();
    assert(data.id, "Response should have an id");
  });

  await test("POST /api/products with no body returns 400", async () => {
    const r = await fetch(BASE + "/api/products", { method: "POST", headers: { "Authorization": "Bearer " + TEST_TOKEN } });
    assert(r.status === 400, "Expected 400, got " + r.status);
  });

  await test("POST /api/products with empty required field returns 400", async () => {
    const r = await fetch(BASE + "/api/products", {
      method: "POST", headers: AUTH_HEADERS,
      body: JSON.stringify({ name: "" })
    });
    assert(r.status === 400, "Expected 400, got " + r.status);
  });

  await test("DELETE /api/products/:id without auth returns 401", async () => {
    const r = await fetch(BASE + "/api/products/999", { method: "DELETE" });
    assert(r.status === 401, "Expected 401, got " + r.status);
  });

  await test("POST /api/products with name over max length returns 400", async () => {
    const r = await fetch(BASE + "/api/products", {
      method: "POST", headers: AUTH_HEADERS,
      body: JSON.stringify({ name: "xxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxx" })
    });
    assert(r.status === 400, "Expected 400, got " + r.status);
  });

  await test("POST /api/products strips unknown fields (mass assignment protection)", async () => {
    const payload = { ...{"name":"Test value","price":42}, admin: true, role: "superuser" };
    payload["name"] = _uniqueText("name");
    const r = await fetch(BASE + "/api/products", {
      method: "POST", headers: AUTH_HEADERS,
      body: JSON.stringify(payload)
    });
    assert(r.status === 201, "Expected 201, got " + r.status);
    const data = await r.json();
    assert(data.admin === undefined, "admin field should have been stripped");
    assert(data.role === undefined, "role field should have been stripped");
  });

  await test("GET /api/products returns created records after POST", async () => {
    const r = await fetch(BASE + "/api/products");
    const data = await r.json();
    assert(Array.isArray(data), "Expected array");
    assert(data.length > 0, "Expected at least one record (from earlier POST test)");
  });

  console.log("");
  console.log("Results:", passed, "passed,", failed, "failed");
  process.exit(failed > 0 ? 1 : 0);
}

run();